mapper.select:
SELECT A1.NTT_ID , A1.BBS_ID , COALESCE(( SELECT BBS_NM FROM ARMBORD WHERE BBS_ID = A1.BBS_ID) , '') AS BBS_NM , A1.PARNTSCTT_ID , A1.ANSWER_AT , A1.NTT_SJ , A1.NTT_CN , COALESCE(A1.NTT_DATA1, '') AS NTT_DATA1 , COALESCE(A1.NTT_DATA2, '') AS NTT_DATA2 , COALESCE(A1.NTT_DATA3, '') AS NTT_DATA3 , COALESCE(A1.NTT_DATA4, '') AS NTT_DATA4 , COALESCE(A1.NTT_DATA5, '') AS NTT_DATA5 , COALESCE(A1.NTT_DATA6, '') AS NTT_DATA6 , COALESCE(A1.NTT_IMG_FILE_ID, '') AS NTT_IMG_FILE_ID , A1.RDCNT , A1.NTCR_ID , A1.NTCR_NM , CASE WHEN B2.USER_SE = 'USR' THEN '관리자' ELSE FN_MASK_NAME(A1.NTCR_NM) END AS MASK_NTCR_NM , DATE_FORMAT(A1.NTCR_DT, '%Y-%m-%d') AS NTCR_DT , A1.NOTICE_AT , A1.SECRET_AT
, COALESCE(A1.ATCH_FILE_ID, '') AS ATCH_FILE_ID , DATE_FORMAT(A1.NTCR_START_DT, '%Y-%m-%d') AS NTCR_START_DT , DATE_FORMAT(A1.NTCR_END_DT , '%Y-%m-%d') AS NTCR_END_DT , COALESCE(( SELECT COUNT(*) FROM ARTBBSM WHERE PARNTSCTT_ID = A1.NTT_ID) , 0) AS ANSWER_CNT
FROM ARTBBSM A1 LEFT JOIN ARMUSER B2 ON A1.NTCR_ID = B2.ESNTL_ID WHERE A1.BBS_ID = #{bbsId} AND A1.NTT_ID = #{nttId}

