   SET NTT_SJ        = #{nttSj}
     , NTT_CN        = #{nttCn}

     , NTT_DATA1     = #{nttData1}


     , NTT_DATA2     = #{nttData2}


     , NTT_DATA3     = #{nttData3}


     , NTT_DATA4     = #{nttData4}

     , NTT_DATA5     = #{nttData5}
     , NTT_DATA6     = #{nttData6}




     , NTT_IMG_FILE_ID = NULL


     , NTT_IMG_FILE_ID   = #{nttImgFileId}


     , NTCR_START_DT = #{ntcrStartDt}
     , NTCR_END_DT   = #{ntcrEndDt}
     , NOTICE_AT     = COALESCE(#{noticeAt}, 'N')

     , SECRET_AT     = #{secretAt}

     , NTT_CN_FILE_ID  = #{nttCnFileId}
     , ATCH_FILE_ID  = #{atchFileId}

     , ANSWER_AT     = #{answerAt}


     , STTUS_CODE = #{sttusCode}

     , PASSWORD    = #{newPw}

     , CHG_USER_ID   = #{UNIQ_ID}
     , CHG_DATE      = NOW()
 WHERE BBS_ID = #{bbsId}
   AND NTT_ID = #{nttId}

