mapper.select:
SELECT A1.NTT_ID , A1.BBS_ID , B1.BBS_NM , A1.NTT_SJ , DATE_FORMAT(A1.NTCR_DT, '%Y-%m-%d') AS NTCR_DT FROM ARTBBSM A1 INNER JOIN ARMBORD B1 ON A1.BBS_ID = B1.BBS_ID WHERE NOW() >= A1.NTCR_START_DT AND NOW() <= A1.NTCR_END_DT AND A1.STTUS_CODE = 'A' AND A1.ANSWER_AT = 'N' AND A1.BBS_ID IN
#{bbsList}
ORDER BY A1.NTCR_DT DESC LIMIT #{topLimit}
